#include <bits/stdc++.h>
using namespace std;

const int N=3e4+10;

struct Node{
    int son[2],fail;
}tr[N];

int n,tot=1,q[N],hh,tt,dfn[N],sz[N],c[N],num,idx[N],d[N];
char s[N];
vector<int> e[N];
bool b[N];

void Insert(int x){
    int p=1;
    for(int i=1;s[i];i++){
        if(!tr[p].son[s[i]-'0']) tr[p].son[s[i]-'0']=++tot;
        p=tr[p].son[s[i]-'0'];
    }
    idx[x]=p;
}

void build(){
    hh=1,tt=0;
    for(int i=0;i<2;i++)
        if(tr[1].son[i]) {
            q[++tt]=tr[1].son[i];
            tr[tr[1].son[i]].fail=1;
        }else
            tr[1].son[i]=1;
    while(hh<=tt){
        int x=q[hh++];
        e[tr[x].fail].push_back(x);
        for(int i=0;i<2;i++)
            if(tr[x].son[i]){
                q[++tt]=tr[x].son[i];
                tr[tr[x].son[i]].fail=tr[tr[x].fail].son[i];
            }else
                tr[x].son[i]=tr[tr[x].fail].son[i];
    }
}

void dfs(int x){
    dfn[x]=++num;
    sz[x]=1;
    for(int y:e[x]){
        dfs(y);
        sz[x]+=sz[y];
    }
}

int main(){
    scanf("%d",&n);
    for(int i=1;i<=n;i++){
        scanf("%s",s+1);
        Insert(i);
    }
    build();
    dfs(1);
    for(int i=1;i<=n;i++)
        c[dfn[idx[i]]]++,c[dfn[idx[i]]+sz[idx[i]]]--;
    for(int i=1;i<=tot;i++) c[i]+=c[i-1];
    for(int i=1;i<=tot;i++) b[i]=(c[dfn[i]]==0);

    for(int i=1;i<=tot;i++){
        if(!b[i]) continue;
        e[i].clear();
        e[i].push_back(tr[i].son[0]),d[tr[i].son[0]]++;
        e[i].push_back(tr[i].son[1]),d[tr[i].son[1]]++;
    }
    hh=1,tt=0;
    for(int i=1;i<=tot;i++)
        if(b[i] && !d[i]) q[++tt]=i;
    while(hh<=tt){
        int x=q[hh++];
        for(int y:e[x])
            if(b[y]){
                d[y]--;
                if(!d[y]) q[++tt]=y;
            }
    }
    bool flag=true;
    for(int i=1;i<=tot && flag;i++)
        if(b[i] && d[i]) flag=false;
    if(flag)
        puts("NIE");
    else
        puts("TAK");
    return 0;
}
